#include <stdio.h>
#include <stdbool.h>

static inline bool isVowel(char c){return c=='a'||c=='e'||c=='i'||c=='o'||c=='u';}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char S[105]; scanf("%s", S);
        char dq[210]; int front=105, back=105; // middle of array
        bool rev=false;
        for(int i=0;i<N;i++){
            char c=S[i];
            if(isVowel(c)) rev=!rev;
            if(rev) dq[--front]=c; // push front
            else dq[back++]=c;      // push back
        }
        for(int i=front;i<back;i++) putchar(dq[i]);
        putchar('\n');
    }
    return 0;
}

